        Ok(s) => s,
        Err(e) => return Some(e),
    };

    let binary = match &world.binary_path {
        Some(p) => p.clone(),
        None => return Some(StepResult::fail("binary path not set")),
    };

    Some(run_binary(&binary, &args_str, world))
}

